def f(lst):
    if not lst:
        return None
    candidate = None
    count = 0
    for num in lst:
        if count == 0:
            candidate = num
            count = 1
        elif num == candidate:
            count += 1
        else:
            count -= 1
    if lst.count(candidate) > len(lst) // 2:
        return candidate
    return None
